          </div>
        ) : (
          <div className="text-center py-8 text-gray-500">
            No sales data available for today
          </div>
        )}
      </CardContent>
    </Card>
  );
}
// Keep existing FoodMenu component (unchanged)
function FoodMenu({ mode }) {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(false);
  const [newItem, setNewItem] = useState({
    name: "",
    alpha_code: "",
    numeric_code: "",
    price_fixed: "",
    price_general: "",
    price_ac: "",
    category: "",
  });

  const load = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API}/menu`);
      setItems(safeArray(res.data));
    } catch (e) {
      console.error("Menu load error:", e);
      toast.error("Failed to load menu");
      setItems([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const handleNewItemChange = (e) => {
    const { name, value } = e.target;
    setNewItem((prev) => ({ ...prev, [name]: value }));
  };

  const handleAddItem = async () => {
    if (!newItem.name || (!newItem.alpha_code && !newItem.numeric_code)) {
      toast.error("Please provide item name and at least one code");
      return;
    }

    try {
      await axios.post(`${API}/menu`, {
        ...newItem,
        price_fixed: parseFloat(newItem.price_fixed) || 0,
        price_general: parseFloat(newItem.price_general) || 0,
        price_ac: parseFloat(newItem.price_ac) || 0,
      });

      toast.success("Item added successfully");
      setNewItem({
        name: "",
        alpha_code: "",
        numeric_code: "",
        price_fixed: "",
        price_general: "",
        price_ac: "",
        category: "",
      });
      load();
    } catch (e) {
      console.error("Add item error:", e);
      toast.error(safeGet(e, "response.data.detail", "Failed to add item"));
    }
  };

  const handleDeleteItem = async (itemId) => {
    if (!window.confirm("Are you sure you want to delete this item?")) {
      return;
    }

    try {
      await axios.delete(`${API}/menu/${itemId}`);
      toast.success("Item deleted successfully");
      load();
    } catch (e) {
      console.error("Delete item error:", e);
      toast.error(safeGet(e, "response.data.detail", "Failed to delete item"));
    }
  };

  if (loading) {
    return (
      <Card>
        <CardContent className="text-center py-8">
          <Loader2 size={24} className="mb-2" />
          <span>Loading menu...</span>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <ChefHat size={20} />
          Food Menu ({items.length} items)
        </CardTitle>
      </CardHeader>
      <CardContent>
        {mode === "admin-full" && (
          <div className="grid grid-cols-7 gap-2 mb-6 p-4 bg-gray-50 rounded-lg">
            <Input
              name="name"
              placeholder="Item Name"
              value={newItem.name}
              onChange={handleNewItemChange}
            />
            <Input
              name="alpha_code"
              placeholder="Alpha Code"
              value={newItem.alpha_code}
              onChange={handleNewItemChange}
            />
            <Input
              name="numeric_code"
              placeholder="Numeric Code"
              value={newItem.numeric_code}
              onChange={handleNewItemChange}
            />
            <Input
              name="price_fixed"
              type="number"
              step="0.01"
              placeholder="Fixed Price"
              value={newItem.price_fixed}
              onChange={handleNewItemChange}
            />
            <Input
              name="price_general"
              type="number"
              step="0.01"
              placeholder="General Price"
              value={newItem.price_general}
              onChange={handleNewItemChange}
            />
            <Input
              name="price_ac"
              type="number"
              step="0.01"
              placeholder="AC Price"
              value={newItem.price_ac}
              onChange={handleNewItemChange}
            />
            <Input
              name="category"
              placeholder="Category"
              value={newItem.category}
              onChange={handleNewItemChange}
            />
            <Button onClick={handleAddItem} className="col-span-7">
              <Plus size={16} className="mr-2" />
              Add Item
            </Button>
          </div>
        )}

        {items.length === 0 ? (
          <div className="text-center py-8 text-gray-500">
            No menu items found.{" "}
            {mode === "admin-full" && "Add some items above to get started."}
          </div>
        ) : (
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Item Name</TableHead>
                <TableHead>Alpha Code</TableHead>
                <TableHead>Numeric Code</TableHead>
                <TableHead>Fixed Price</TableHead>
                <TableHead>General Price</TableHead>
                <TableHead>AC Price</TableHead>
                <TableHead>Category</TableHead>
                {mode === "admin-full" && <TableHead>Actions</TableHead>}
              </TableRow>
            </TableHeader>
            <TableBody>
              {items.map((item) => (
                <TableRow key={safeGet(item, "id", Math.random())}>
                  <TableCell>{safeGet(item, "name", "N/A")}</TableCell>
                  <TableCell>{safeGet(item, "alpha_code", "-")}</TableCell>
                  <TableCell>{safeGet(item, "numeric_code", "-")}</TableCell>
                  <TableCell>
                    â‚¹ {Number(safeGet(item, "price_fixed", 0)).toFixed(2)}
                  </TableCell>
                  <TableCell>
                    â‚¹ {Number(safeGet(item, "price_general", 0)).toFixed(2)}
                  </TableCell>
                  <TableCell>
                    â‚¹ {Number(safeGet(item, "price_ac", 0)).toFixed(2)}
                  </TableCell>
                  <TableCell>{safeGet(item, "category", "-")}</TableCell>
                  {mode === "admin-full" && (
                    <TableCell>
                      <Button
                        variant="destructive"
                        size="sm"
                        onClick={() => handleDeleteItem(safeGet(item, "id"))}
                      >
                        <Trash2 size={14} />
                      </Button>
                    </TableCell>
                  )}
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </CardContent>
    </Card>
  );
}

// Enhanced Billing component with shift context
function Billing({
  drafts = {},
  setDrafts,
  currentTable = "",
  setCurrentTable,
  billingDate,
  activeTab,
  track = "",
  sessionId = null,
}) {
  const [entryCode, setEntryCode] = useState("");
  const [qty, setQty] = useState(1);
  const [nextBillNumber, setNextBillNumber] = useState(null);
  const [loading, setLoading] = useState(false);

  const tableNoRef = useRef(null);
  const itemCodeRef = useRef(null);
  const qtyRef = useRef(null);

  const [showHelp, setShowHelp] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [menuItems, setMenuItems] = useState([]);
  const [filteredItems, setFilteredItems] = useState([]);
  const [selectedHelpIndex, setSelectedHelpIndex] = useState(0);
  const searchInputRef = useRef(null);

  const currentDraft = useMemo(() => {
    const defaultDraft = {
      header: {
        table_no: currentTable || "",
        party_no: "1",
        section: "G",
        track: track || "",
        bill_number: null,
      },
      lines: [],
      modified_from_bill_id: null,
    };

    if (!drafts || !currentTable) {
      return defaultDraft;
    }

    const draft = drafts[currentTable];
    if (!draft) {
      return defaultDraft;
    }

    return {
      header: safeObject(draft.header, defaultDraft.header),
      lines: safeArray(draft.lines, []),
      modified_from_bill_id: draft.modified_from_bill_id || null,
    };
  }, [drafts, currentTable, track]);

  // Load menu for help system
  useEffect(() => {
    const loadMenu = async () => {
      try {
        const res = await axios.get(`${API}/menu`);
        const items = safeArray(res.data);
        setMenuItems(items);
        setFilteredItems(items);
      } catch (e) {
        console.error("Failed to load menu for help:", e);
        toast.error("Failed to load menu for help panel");
        setMenuItems([]);
        setFilteredItems([]);
      }
    };
    loadMenu();
  }, []);

  // Focus management
  useEffect(() => {
    if (activeTab === "billing" && tableNoRef.current) {
      tableNoRef.current.focus();
    }
  }, [activeTab]);

  // Enhanced bill printing with shift context
  const handlePrintBill = async () => {
    if (!currentTable) {
      toast.error("Please enter a table number before printing.");
      return;
    }

    let finalLines = safeArray(currentDraft.lines);
    if (document.activeElement === qtyRef.current && entryCode) {
      const newItem = await addItem(false);
      if (newItem) {
        finalLines = [...finalLines, newItem];
      } else {
        return;
      }
    }

    if (finalLines.length === 0) {
      toast.error("Please add at least one item to the bill.");
      return;
    }

    await createBill(finalLines);
  };

  // Global keyboard shortcuts
  useEffect(() => {
    const handleGlobalKeyDown = (event) => {
      if (event.key === "End" || event.key === "Home") {
        event.preventDefault();
        handlePrintBill();
      }
    };

    window.addEventListener("keydown", handleGlobalKeyDown);
    return () => {
      window.removeEventListener("keydown", handleGlobalKeyDown);
    };
  }, [currentTable, entryCode, qty, currentDraft.lines]);

  // Fetch next bill number
  useEffect(() => {
    if (billingDate) {
      const fetchNextBillNumber = async () => {
        try {
          const res = await axios.get(`${API}/bill/next_number`, {
            params: { bill_date: billingDate },
          });
          setNextBillNumber(safeGet(res, "data.bill_number", 1));
        } catch (e) {
          console.error("Failed to fetch bill number:", e);
          toast.error("Failed to fetch next bill number.");
          setNextBillNumber(1);
        }
      };
      fetchNextBillNumber();
    }
  }, [billingDate]);

  const onHeaderChange = (patch) => {
    if (!currentTable || !setDrafts) return;

    const newHeader = {
      ...safeObject(currentDraft.header),
      ...patch,
    };

    const newDraft = {
      ...currentDraft,
      header: newHeader,
    };

    setDrafts((prev) => ({
      ...safeObject(prev),
      [currentTable]: newDraft,
    }));
  };

  const setSectionByTable = (tableNo) => {
    const table = parseInt(tableNo, 10);
    if (isNaN(table)) return;

    let section = "G";
    if (table === 1) {
      section = "P";
    } else if (table >= 15 && table <= 30) {
      section = "AC";
    }
    onHeaderChange({ section });
  };

  const loadDataForTable = async (tableNo) => {
    if (!tableNo || !setDrafts) return;
    setSectionByTable(tableNo);
    if (drafts && drafts[tableNo]) return;

    try {
      const res = await axios.get(`${API}/bill/last`, {
        params: { table_no: tableNo, bill_date: billingDate },
      });

      const lastBill = res.data;
      setDrafts((prev) => ({
        ...safeObject(prev),
        [tableNo]: {
          header: safeObject(lastBill.header, {
            table_no: tableNo,
            party_no: "1",
            section: "G",
            bill_number: null,
          }),
          lines: safeArray(lastBill.items),
          modified_from_bill_id: lastBill.id,
        },
      }));
      toast.success(`Loaded last bill for table ${tableNo}`);
    } catch (e) {
      console.error("Error loading table data:", e);
      setDrafts((prev) => ({
        ...safeObject(prev),
        [tableNo]: {
          header: {
            table_no: tableNo,
            party_no: "1",
            section: "G",
            bill_number: null,
          },
          lines: [],
        },
      }));
    }
  };

  const handleTableNoKeyDown = (event) => {
    if (event.key === "PageDown") {
      if (itemCodeRef.current) {
        itemCodeRef.current.focus();
      }
    } else if (event.key === "Enter") {
      const newTableNo = event.target.value;
      if (setCurrentTable) {
        setCurrentTable(newTableNo);
      }
      loadDataForTable(newTableNo);
    }
  };

  const addItem = async (focusItemCode = true) => {
    if (!entryCode || !currentTable) return null;

    try {
      const res = await axios.get(`${API}/menu/lookup/${entryCode}`);
      const item = res.data;

      if (!item) {
        toast.error("Item not found");
        return null;
      }

      const section = safeGet(currentDraft, "header.section", "G");
      let unitPrice;

      switch (section) {
        case "AC":
          unitPrice = safeGet(item, "price_ac", 0);
          break;
        case "P":
          unitPrice = safeGet(item, "price_fixed", 0);
          break;
        default:
          unitPrice = safeGet(item, "price_general", 0);
      }

      const newLine = {
        code: entryCode.toUpperCase(),
        name: safeGet(item, "name", "Unknown Item"),
        quantity: qty || 1,
        unit_price: Number(unitPrice),
        line_total: Number((unitPrice * (qty || 1)).toFixed(2)),
      };

      if (focusItemCode && setDrafts) {
        const updatedLines = [...safeArray(currentDraft.lines), newLine];
        setDrafts((prev) => ({
          ...safeObject(prev),
          [currentTable]: {
            ...currentDraft,
            lines: updatedLines,
          },
        }));
        setEntryCode("");
        setQty(1);
        if (itemCodeRef.current) {
          itemCodeRef.current.focus();
        }
      }

      return newLine;
    } catch (e) {
      console.error("Add item error:", e);
      toast.error(safeGet(e, "response.data.detail", "Item not found"));
      return null;
    }
  };

  const handleItemCodeKeyDown = (e) => {
    if (e.key === "F1") {
      e.preventDefault();
      setShowHelp(true);
    } else if (e.key === "Escape") {
      e.preventDefault();
      setShowHelp(false);
      if (itemCodeRef.current) {
        itemCodeRef.current.focus();
      }
    } else if (e.key === "Enter" && entryCode) {
      e.preventDefault();
      const item = menuItems.find(
        (i) =>
          safeGet(i, "numeric_code") === entryCode ||
          safeGet(i, "alpha_code", "").toLowerCase() === entryCode.toLowerCase()
      );
      if (item) {
        if (qtyRef.current) {
          qtyRef.current.focus();
          qtyRef.current.select();
        }
      } else {
        setShowHelp(true);
      }
    }
  };

  const handleQtyKeyDown = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      addItem();
    }
  };

  const updateQty = (index, newQty) => {
    if (!setDrafts || !currentTable) return;
    if (newQty <= 0) {
      removeLine(index);
      return;
    }

    const lines = safeArray(currentDraft.lines);
    const updatedLines = lines.map((l, i) => {
      if (i !== index) return l;
      return {
        ...l,
        quantity: newQty,
        line_total: Number((safeGet(l, "unit_price", 0) * newQty).toFixed(2)),
      };
    });

    setDrafts((prev) => ({
      ...safeObject(prev),
      [currentTable]: {
        ...currentDraft,
        lines: updatedLines,
      },
    }));
  };

  const removeLine = (index) => {
    if (!setDrafts || !currentTable) return;
    const lines = safeArray(currentDraft.lines);
    const updatedLines = lines.filter((_, i) => i !== index);
    setDrafts((prev) => ({
      ...safeObject(prev),
      [currentTable]: {
        ...currentDraft,
        lines: updatedLines,
      },
    }));
  };

  const subtotal = useMemo(() => {
    const lines = safeArray(currentDraft.lines);
    return lines.reduce((s, l) => s + Number(safeGet(l, "line_total", 0)), 0);
  }, [currentDraft.lines]);

  const sgst = useMemo(() => Number((subtotal * 0.025).toFixed(2)), [subtotal]);
  const cgst = useMemo(() => Number((subtotal * 0.025).toFixed(2)), [subtotal]);
  const total = useMemo(
    () => Number((subtotal + sgst + cgst).toFixed(2)),
    [subtotal, sgst, cgst]
  );

  // Enhanced createBill with session context
  const createBill = async (lines) => {
    if (!lines || lines.length === 0) {
      toast.error("No items to bill");
      return;
    }

    setLoading(true);
    const header = safeObject(currentDraft.header);

    try {
      const payload = {
        header: {
          table_no: safeGet(header, "table_no", currentTable),
          party_no: safeGet(header, "party_no", "1"),
          section: safeGet(header, "section", "G"),
          track: safeGet(header, "track", track),
          clerk_initials: "CLK",
        },
        item_codes: lines.map((l) => safeGet(l, "code", "")),
        quantities: lines.map((l) => safeGet(l, "quantity", 1)),
        bill_date: billingDate,
        modified_from_bill_id: currentDraft.modified_from_bill_id,
        session_id: sessionId, // Include session context
      };

      const res = await axios.post(`${API}/bill`, payload);
      const billData = res.data;
      const billNumber = safeGet(billData, "header.bill_number", "Unknown");

      toast.success(`Bill #${billNumber} created`);

      if (typeof window !== "undefined") {
        window.printBillData = billData;
      }

      if (setDrafts) {
        setDrafts((prev) => {
          const newDrafts = { ...safeObject(prev) };
          delete newDrafts[currentTable];
          return newDrafts;
        });
      }

      if (setCurrentTable) {
        setCurrentTable("");
      }

      setEntryCode("");
      setQty(1);
      setNextBillNumber(Number(safeGet(billData, "header.bill_number", 0)) + 1);

      setTimeout(() => {
        window.print();
        if (tableNoRef.current) {
          tableNoRef.current.focus();
        }
      }, 200);
    } catch (e) {
      console.error("Bill creation error:", e);
      toast.error(safeGet(e, "response.data.detail", "Failed to create bill"));
    } finally {
      setLoading(false);
    }
  };

  const displayBillNumber =
    safeGet(currentDraft, "header.bill_number") !== null
      ? safeGet(currentDraft, "header.bill_number")
      : nextBillNumber;

  // Help system logic (keeping existing functionality)
  useEffect(() => {
    if (showHelp) {
      setSearchQuery("");
      setFilteredItems([...menuItems]);
      setSelectedHelpIndex(0);
      setTimeout(() => {
        if (searchInputRef.current) {
          searchInputRef.current.focus();
        }
      }, 0);
    }
  }, [showHelp, menuItems]);

  useEffect(() => {
    const lowercasedQuery = searchQuery.toLowerCase();
    const filtered = menuItems.filter(
      (item) =>
        safeGet(item, "name", "").toLowerCase().includes(lowercasedQuery) ||
        safeGet(item, "numeric_code", "")
          .toLowerCase()
          .includes(lowercasedQuery) ||
        safeGet(item, "alpha_code", "").toLowerCase().includes(lowercasedQuery)
    );
    setFilteredItems(filtered);
    setSelectedHelpIndex(0);
  }, [searchQuery, menuItems]);

  const handleSearchKeyDown = (e) => {
    const itemsLength = filteredItems.length;
    if (e.key === "ArrowDown") {
      e.preventDefault();
      setSelectedHelpIndex((prev) => (prev + 1) % itemsLength);
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      setSelectedHelpIndex((prev) => (prev - 1 + itemsLength) % itemsLength);
    } else if (e.key === "Enter") {
      e.preventDefault();
      if (filteredItems[selectedHelpIndex]) {
        const selectedItem = filteredItems[selectedHelpIndex];
        setEntryCode(
          safeGet(selectedItem, "numeric_code", "") ||
            safeGet(selectedItem, "alpha_code", "")
        );
        setShowHelp(false);
        if (qtyRef.current) {
          qtyRef.current.focus();
          qtyRef.current.select();
        }
      }
    } else if (e.key === "Escape") {
      e.preventDefault();
      setShowHelp(false);
      if (itemCodeRef.current) {
        itemCodeRef.current.focus();
      }
    }
  };

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <FileText size={20} />
            Billing for {billingDate}
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-4 gap-4 mb-4">
            <div>
              <Label>Table No</Label>
              <Input
                ref={tableNoRef}
                placeholder="Type & Enter"
                value={currentTable}
                onChange={(e) =>
                  setCurrentTable && setCurrentTable(e.target.value)
                }
                onKeyDown={handleTableNoKeyDown}
              />
            </div>
            <div>
              <Label>Party No.</Label>
              <Input
                value={safeGet(currentDraft, "header.party_no", "")}
                onChange={(e) => onHeaderChange({ party_no: e.target.value })}
              />
            </div>
            <div>
              <Label>Section</Label>
              <Input
                value={safeGet(currentDraft, "header.section", "G")}
                readOnly
              />
            </div>
            <div>
              <Label>Bill No.</Label>
              <Input value={displayBillNumber || "..."} readOnly />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4 mb-4">
            <div>
              <Label>Item Code (F1 for Help)</Label>
              <Input
                ref={itemCodeRef}
                type="text"
                placeholder="Enter Item Code"
                value={entryCode}
                onChange={(e) => setEntryCode(e.target.value)}
                onKeyDown={handleItemCodeKeyDown}
              />
            </div>
            <div>
              <Label>Quantity</Label>
              <Input
                ref={qtyRef}
                type="number"
                min="1"
                value={qty}
                onChange={(e) => setQty(Number(e.target.value) || 1)}
                onKeyDown={handleQtyKeyDown}
              />
            </div>
          </div>

          <div className="mb-4">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>No.</TableHead>
                  <TableHead>Item</TableHead>
                  <TableHead>Qty</TableHead>
                  <TableHead>Rate</TableHead>
                  <TableHead>Amount</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {safeArray(currentDraft.lines).map((l, idx) => (
                  <TableRow key={idx}>
                    <TableCell>{idx + 1}</TableCell>
                    <TableCell>
                      {safeGet(l, "name", "Unknown Item")}
                      <Button
                        variant="destructive"
                        size="sm"
                        className="ml-2"
                        onClick={() => removeLine(idx)}
                      >
                        <Minus size={12} />
                      </Button>
                    </TableCell>
                    <TableCell>
                      <Input
                        type="number"
                        min="1"
                        className="w-16"
                        value={safeGet(l, "quantity", 0)}
                        onChange={(e) =>
                          updateQty(idx, Number(e.target.value) || 1)
                        }
                      />
                    </TableCell>
                    <TableCell>
                      â‚¹ {Number(safeGet(l, "unit_price", 0)).toFixed(2)}
                    </TableCell>
                    <TableCell>
                      â‚¹ {Number(safeGet(l, "line_total", 0)).toFixed(2)}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>

      <div className="grid grid-cols-2 gap-6">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <HelpCircle size={20} />
              Help
            </CardTitle>
          </CardHeader>
          <CardContent>
            {!showHelp && (
              <div className="space-y-3">
                <p className="text-sm text-gray-600">
                  Press F1 in Item Code to search for items.
                </p>
                <div>
                  <h4 className="font-medium mb-2">Keyboard Shortcuts</h4>
                  <ul className="text-sm text-gray-600 space-y-1">
                    <li>â€¢ F1: Open item search in Help Panel</li>
                    <li>â€¢ Esc: Close item search in Help Panel</li>
                    <li>â€¢ Enter: Move between fields / Add item</li>
                    <li>â€¢ Arrow Up/Down: Navigate search results</li>
                    <li>â€¢ PageDown: Move from Table No. to Item Code</li>
                    <li>â€¢ End / Home: Finalize and Print Bill</li>
                  </ul>
                </div>
              </div>
            )}

            {showHelp && (
              <div>
                <Input
                  ref={searchInputRef}
                  type="text"
                  placeholder="Search by code or name..."
                  className="mb-4"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  onKeyDown={handleSearchKeyDown}
                />

                {filteredItems.length === 0 ? (
                  <div className="text-center py-4 text-gray-500">
                    No items found
                  </div>
                ) : (
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Code</TableHead>
                        <TableHead>Name</TableHead>
                        <TableHead>Price</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {filteredItems.map((item, index) => (
                        <TableRow
                          key={safeGet(item, "id", Math.random())}
                          className={`cursor-pointer hover:bg-gray-100 ${
                            selectedHelpIndex === index ? "bg-blue-100" : ""
                          }`}
                          onClick={() => {
                            setEntryCode(
                              safeGet(item, "numeric_code", "") ||
                                safeGet(item, "alpha_code", "")
                            );
                            setShowHelp(false);
                            if (qtyRef.current) {
                              qtyRef.current.focus();
                              qtyRef.current.select();
                            }
                          }}
                        >
                          <TableCell>
                            {safeGet(item, "numeric_code", "") ||
                              safeGet(item, "alpha_code", "") ||
                              "-"}
                          </TableCell>
                          <TableCell>
                            {safeGet(item, "name", "Unknown")}
                          </TableCell>
                          <TableCell>
                            â‚¹{" "}
                            {Number(safeGet(item, "price_general", 0)).toFixed(
                              2
                            )}
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                )}
              </div>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Finalize Bill</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              <div className="flex justify-between">
                <span>Subtotal:</span>
                <span>â‚¹{subtotal.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span>SGST (2.5%):</span>
                <span>â‚¹{sgst.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span>CGST (2.5%):</span>
                <span>â‚¹{cgst.toFixed(2)}</span>
              </div>
              <div className="flex justify-between font-bold text-lg border-t pt-2">
                <span>Grand Total:</span>
                <span>â‚¹{total.toFixed(2)}</span>
              </div>
              <Button
                onClick={handlePrintBill}
                disabled={loading || safeArray(currentDraft.lines).length === 0}
                className="w-full"
                size="lg"
              >
                {loading ? (
                  <Loader2 size={16} className="mr-2" />
                ) : (
                  <Printer size={16} className="mr-2" />
                )}
                Print Bill
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}
// RecentBills component (unchanged)
function RecentBills({ billingDate }) {
  const [bills, setBills] = useState([]);
  const [loading, setLoading] = useState(false);

  const loadRecentBills = async () => {
    if (!billingDate) return;
    setLoading(true);
    try {
      const res = await axios.get(`${API}/bills/by_date`, {
        params: { bill_date: billingDate },
      });
      setBills(safeArray(res.data));
    } catch (e) {
      console.error("Failed to load recent bills:", e);
      toast.error("Failed to load recent bills.");
      setBills([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadRecentBills();
  }, [billingDate]);

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <History size={20} />
          Recent Bills for {billingDate || "No Date Selected"}
        </CardTitle>
      </CardHeader>
      <CardContent>
        {loading ? (
          <div className="text-center py-8">
            <Loader2 size={24} className="mb-2" />
            <span>Loading bills...</span>
          </div>
        ) : bills.length === 0 ? (
          <div className="text-center py-8 text-gray-500">
            No bills found for this date.
          </div>
        ) : (
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Bill No</TableHead>
                <TableHead>Table</TableHead>
                <TableHead>Time</TableHead>
                <TableHead>Amount</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {bills.map((bill) => (
                <TableRow key={safeGet(bill, "id", Math.random())}>
                  <TableCell>{safeGet(bill, "bill_number", "N/A")}</TableCell>
                  <TableCell>{safeGet(bill, "table_no", "N/A")}</TableCell>
                  <TableCell>
                    {safeGet(bill, "created_at")
                      ? new Date(bill.created_at).toLocaleTimeString()
                      : "N/A"}
                  </TableCell>
                  <TableCell>
                    â‚¹ {Number(safeGet(bill, "grand_total", 0)).toFixed(2)}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </CardContent>
    </Card>
  );
}

// Settings Editor component (unchanged)
function SettingsEditor({ settings, onChange }) {
  const [form, setForm] = useState(safeObject(settings));
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    setForm(safeObject(settings));
  }, [settings]);

  const save = async () => {
    setLoading(true);
    try {
      const res = await axios.put(`${API}/settings`, form);
      if (onChange) {
        onChange(res.data);
      }
      toast.success("Settings saved");
    } catch (e) {
      console.error("Settings save error:", e);
      toast.error(
        safeGet(e, "response.data.detail", "Failed to save settings")
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Settings size={20} />
          Receipt Settings
        </CardTitle>
      </CardHeader>
      <CardContent>
        <Table>
          <TableBody>
            <TableRow>
              <TableCell>Hotel Name</TableCell>
              <TableCell>
                <Input
                  value={safeGet(form, "hotel_name", "")}
                  onChange={(e) =>
                    setForm({ ...form, hotel_name: e.target.value })
                  }
                />
              </TableCell>
            </TableRow>
            <TableRow>
              <TableCell>Phone</TableCell>
              <TableCell>
                <Input
                  value={safeGet(form, "phone", "")}
                  onChange={(e) => setForm({ ...form, phone: e.target.value })}
                />
              </TableCell>
            </TableRow>
            <TableRow>
              <TableCell>GSTIN</TableCell>
              <TableCell>
                <Input
                  value={safeGet(form, "gstin", "")}
                  onChange={(e) => setForm({ ...form, gstin: e.target.value })}
                />
              </TableCell>
            </TableRow>
            <TableRow>
              <TableCell>Address</TableCell>
              <TableCell>
                <Textarea
                  rows={2}
                  value={safeGet(form, "address", "")}
                  onChange={(e) =>
                    setForm({ ...form, address: e.target.value })
                  }
                />
              </TableCell>
            </TableRow>
          </TableBody>
        </Table>
        <div className="mt-4">
          <Button onClick={save} disabled={loading} className="w-full">
            {loading ? (
              <Loader2 size={16} className="mr-2" />
            ) : (
              <Save size={16} className="mr-2" />
            )}
            Save Settings
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

// Enhanced Admin Panel with new features
function EnhancedAdminPanel({ mode, sessionId }) {
  const [settings, setSettings] = useState(null);
  const [loading, setLoading] = useState(false);
  const [adminActiveTab, setAdminActiveTab] = useState("dashboard");

  const loadSettings = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API}/settings`);
      setSettings(safeObject(res.data));
    } catch (e) {
      console.error("Failed to load settings:", e);
      toast.error("Failed to load settings");
      setSettings({});
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (mode === "admin-full") {
      loadSettings();
    }
  }, [mode]);

  const isAdmin = mode && mode.includes("admin");

  if (!isAdmin) return null;

  return (
    <div className="space-y-6">
      <Tabs value={adminActiveTab} onValueChange={setAdminActiveTab}>
        <TabsList>
          <TabsTrigger value="dashboard">ðŸ“Š Dashboard</TabsTrigger>
          <TabsTrigger value="reports">ðŸ“ˆ Reports</TabsTrigger>
          <TabsTrigger value="reconciliation">ðŸ’° Reconciliation</TabsTrigger>
          <TabsTrigger value="settings">âš™ï¸ Settings</TabsTrigger>
        </TabsList>

        <TabsContent value="dashboard">
          <div className="space-y-6">
            <TopItemsDashboard sessionId={sessionId} />
          </div>
        </TabsContent>

        <TabsContent value="reports">
          <div className="space-y-6">
            <Tabs value="time-range" onValueChange={() => {}}>
              <TabsList>
                <TabsTrigger value="time-range">Time Range</TabsTrigger>
                <TabsTrigger value="date-range">Date Range</TabsTrigger>
                <TabsTrigger value="shift-report">Shift Report</TabsTrigger>
                <TabsTrigger value="item-report">Item Report</TabsTrigger>
              </TabsList>

              <TabsContent value="time-range">
                <TimeRangeReport sessionId={sessionId} />
              </TabsContent>

              <TabsContent value="date-range">
                <DateRangeReport sessionId={sessionId} />
              </TabsContent>

              <TabsContent value="shift-report">
                <ShiftReport sessionId={sessionId} />
              </TabsContent>

              <TabsContent value="item-report">
                <ItemReport sessionId={sessionId} />
              </TabsContent>
            </Tabs>
          </div>
        </TabsContent>

        <TabsContent value="reconciliation">
          <EnhancedReconciliation sessionId={sessionId} mode={mode} />
        </TabsContent>

        <TabsContent value="settings">
          {loading ? (
            <Card>
              <CardContent className="text-center py-8">
                <Loader2 size={24} className="mb-2" />
                <span>Loading settings...</span>
              </CardContent>
            </Card>
          ) : (
            <SettingsEditor settings={settings} onChange={setSettings} />
          )}
        </TabsContent>
      </Tabs>
    </div>
  );
}

// Main App Component with all enhancements
function App() {
  const [mode, setMode] = useState("none");
  const [billingDate, setBillingDate] = useState(null);
  const [track, setTrack] = useState("");
  const [sessionId, setSessionId] = useState(null);
  const [shiftId, setShiftId] = useState(null);
  const [isVerifyingAdmin, setIsVerifyingAdmin] = useState(false);

  const isAdmin = mode && mode.includes("admin");
  const isClerk = mode === "clerk";

  const [drafts, setDrafts] = useState({});
  const [currentTable, setCurrentTable] = useState("");
  const [activeTab, setActiveTab] = useState("billing");

  const handleLogin = (newMode, date, newTrack, newSessionId, newShiftId) => {
    setMode(newMode);
    setBillingDate(date);
    setTrack(newTrack);
    setSessionId(newSessionId);
    setShiftId(newShiftId);
    setIsVerifyingAdmin(false);
  };

  const handleStartAdminVerification = (date, newTrack) => {
    setBillingDate(date);
    setTrack(newTrack);
    setIsVerifyingAdmin(true);
  };

  const handleVerificationComplete = (adminMode) => {
    setMode(adminMode);
    setIsVerifyingAdmin(false);
    toast.success(`Logged in as ${adminMode}`);
  };

  // Logout function
  const handleLogout = () => {
    setMode("none");
    setBillingDate(null);
    setTrack("");
    setSessionId(null);
    setShiftId(null);
    setDrafts({});
    setCurrentTable("");
    setActiveTab("billing");
  };

  return (
    <div className="min-h-screen bg-gradient-to-b from-amber-50 to-orange-50 p-4">
      <div className="max-w-7xl mx-auto">
        <div className="text-center mb-6">
          <h1 className="text-3xl font-bold text-gray-900 tracking-tight">
            Udupi Anand Bhavan — Billing System
          </h1>
          {mode !== "none" && billingDate && (
            <div className="mt-2 text-sm text-gray-600">
              Mode: {mode} | Date: {billingDate} | Track: {track || "Default"}
              <Button
                variant="outline"
                size="sm"
                onClick={handleLogout}
                className="ml-4"
              >
                Logout
              </Button>
            </div>
          )}
        </div>

        {mode === "none" ? (
          isVerifyingAdmin ? (
            <AdminVerificationScreen
              onVerificationComplete={handleVerificationComplete}
            />
          ) : (
            <div className="flex justify-center">
              <LoginPanel
                onLogin={handleLogin}
                onStartAdminVerification={handleStartAdminVerification}
              />
            </div>
          )
        ) : (
          <div className="space-y-6">
            <Tabs value={activeTab} onValueChange={setActiveTab}>
              <TabsList>
                <TabsTrigger value="billing">ðŸ“„ Billing</TabsTrigger>
                <TabsTrigger value="shifts">ðŸ• Shifts</TabsTrigger>
                <TabsTrigger value="menu">ðŸ‘¨â€ðŸ³ Food Menu</TabsTrigger>
                {isAdmin && (
                  <TabsTrigger value="admin">âš™ï¸ Admin</TabsTrigger>
                )}
              </TabsList>

              <TabsContent value="billing">
                <Billing
                  drafts={drafts}
                  setDrafts={setDrafts}
                  currentTable={currentTable}
                  setCurrentTable={setCurrentTable}
                  billingDate={billingDate}
                  activeTab={activeTab}
                  track={track}
                  sessionId={sessionId}
                />
              </TabsContent>

              <TabsContent value="shifts">
                <ShiftTab
                  mode={mode}
                  sessionId={sessionId}
                  currentShift={track}
                  currentDate={billingDate}
                />
              </TabsContent>

              <TabsContent value="menu">
                <FoodMenu mode={mode} />
              </TabsContent>


              {isAdmin && (
                <TabsContent value="admin">
                  <EnhancedAdminPanel mode={mode} sessionId={sessionId} />
                </TabsContent>
              )}
            </Tabs>
          </div>
        )}
      </div>

      {/* Hidden print area */}
      <div className="hidden">
        <BillPrint />
      </div>
    </div>
  );
}
export default App;
